// Test all exam pages for 2025-26 S5 Term2
const baseUrl = 'https://ai-lish.github.io/ai-learning/exam/2025-26-s5-term2';

// Main exam pages
const pages = [
  { url: baseUrl + '/index.html', name: 'index', expected: true },
  { url: baseUrl + '/p1.html', name: 'p1', expected: true },
  { url: baseUrl + '/p2.html', name: 'p2', expected: true }
];

// p1 questions (q1-q22)
for (let i = 1; i <= 22; i++) {
  pages.push({ url: baseUrl + '/p1/q' + i + '.html', name: 'p1-q' + i, expected: true });
}

// p1-ms solutions (q18, q19, q21, q22 have dynamic visualization)
['18', '19', '21', '22'].forEach(q => {
  pages.push({ url: baseUrl + '/p1-ms/q' + q + '.html', name: 'p1-ms-q' + q, expected: true });
});

$json = { pages, _toReturn: [{name: 'start'}] };
return [{json: {pages}}];

// Collect all results
const results = $input.all().map(item => ({
  name: item.json.name,
  url: item.json.url,
  status: item.json.statusCode,
  success: item.json.statusCode === 200
}));

const failed = results.filter(r => !r.success);

$json = {
  total: results.length,
  success: results.filter(r => r.success).length,
  failedCount: failed.length,
  failedPages: failed.map(f => f.name + ': ' + f.status)
};

return [{json: $json}];
